import{V as r}from"./chunks/theme.DQFQySEi.js";import{o,h as s,l as t,b as a,H as i,a2 as n}from"./chunks/framework.GaPwploY.js";const d={style:{margin:"1rem 0"}},v=JSON.parse('{"title":"UI5 Server","description":"","frontmatter":{},"headers":[],"relativePath":"pages/Server.md","filePath":"pages/Server.md"}'),c={name:"pages/Server.md"},m=Object.assign(c,{setup(l){return(h,e)=>(o(),s("div",null,[e[0]||(e[0]=t("h1",{id:"ui5-server",tabindex:"-1"},[a("UI5 Server "),t("a",{class:"header-anchor",href:"#ui5-server","aria-label":'Permalink to "UI5 Server"'},"​")],-1)),e[1]||(e[1]=t("p",null,[a("The "),t("a",{href:"https://github.com/SAP/ui5-server",target:"_blank",rel:"noreferrer"},"UI5 Server"),a(" module provides server capabilities for local development of UI5 projects.")],-1)),t("div",d,[i(r,{class:"no-decoration",text:"📚 API Reference",href:"https://ui5.github.io/cli/v5/api/module-@ui5_server.html"})]),e[2]||(e[2]=n(`<div class="warning custom-block"><p class="custom-block-title">Development Use Only</p><p>The UI5 Server is intended for <strong>local development purposes only</strong>. It must not be exposed to untrusted parties or used as a public-facing web server.</p><p>The server does <strong>not</strong> implement safeguards against various network-based attacks — this is by design, as it is not meant to serve production traffic.</p><p>Please be aware of the following risks when using the server:</p><ul><li><strong>Custom middleware</strong> from third parties can execute arbitrary code on your system and may introduce additional security vulnerabilities when the server is exposed to a network.</li><li><strong>Proxy middleware</strong> configured with credentials may enable unauthorized access to the target system for other parties on the same network.</li><li>Using <code>--accept-remote-connections</code> makes the server reachable from all hosts on your network, which significantly increases the attack surface.</li></ul></div><h2 id="live-status-banner" tabindex="-1">Live Status Banner <a class="header-anchor" href="#live-status-banner" aria-label="Permalink to &quot;Live Status Banner&quot;">​</a></h2><p>When started in an interactive terminal, <code>ui5 serve</code> renders a live status banner that shows the server URLs, the root project&#39;s name/type/version, the configured UI5 framework, and a single-line status indicator that cycles between three states as you work:</p><ul><li><strong>● ready</strong> — the server is idle; no source changes are pending and no build is in flight.</li><li><strong>○ stale · files changed, rebuild on next request</strong> — one or more watched source files changed; the next request will trigger a rebuild.</li><li><strong>◐ building — <em>N</em>/<em>M</em> projects · <em>current project</em> · <em>current task</em></strong> — a build cycle is running. The counter, project name, and task name update in place.</li></ul><p>The status line stays pinned at the bottom of the terminal; warnings and errors scroll above it and remain in your terminal scrollback. While the banner is active, <code>info</code>-level log messages are suppressed — the status line already shows what they would report. The header repaints in place as more information becomes known (project graph resolved, server bound), so early frames may show dim placeholders for sections that have not been populated yet.</p><p>The banner is automatically disabled and <code>ui5 serve</code> falls back to plain log output when:</p><ul><li><code>stderr</code> is not a TTY (e.g. output is piped to a file or another process).</li><li>The log level is set to <code>--silent</code>, <code>--perf</code>, <code>--verbose</code>, or <code>--silly</code> — these levels emit per-task chatter that the status line cannot represent.</li></ul><p>In every other case (the default <code>info</code> level, <code>--loglevel warn</code>, and <code>--loglevel error</code>), the banner is active.</p><h3 id="plain-output-non-tty" tabindex="-1">Plain Output (Non-TTY) <a class="header-anchor" href="#plain-output-non-tty" aria-label="Permalink to &quot;Plain Output (Non-TTY)&quot;">​</a></h3><p>When the banner is disabled, <code>ui5 serve</code> prints the following to <code>stdout</code> once the server is ready:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server started</span></span>
<span class="line"><span>URL: &lt;url&gt;</span></span></code></pre></div><p>The remote-connections warning (when <code>--accept-remote-connections</code> is used) is written to <code>stderr</code>. Tools and scripts that capture the URL by parsing <code>ui5 serve</code> output should run the command in a non-TTY context (pipe, redirect, or CI environment), or pass <code>--verbose</code> to force plain output in an interactive terminal.</p><h2 id="standard-middleware" tabindex="-1">Standard Middleware <a class="header-anchor" href="#standard-middleware" aria-label="Permalink to &quot;Standard Middleware&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Removed Middleware</p><p>The <code>serveThemes</code> middleware has been removed in UI5 CLI v5. Theme compilation is now handled by the <code>buildThemes</code> build task, which pre-compiles all theme CSS files. The resulting CSS files (including <code>library.css</code>, <code>library-RTL.css</code>, <code>library-parameters.json</code>, and CSS Variables resources) are served via the <code>serveResources</code> middleware, providing the same functionality with better performance through build-time compilation and caching.</p><p>The <code>testRunner</code> middleware has also been removed in UI5 CLI v5. The QUnit TestRunner (<code>testrunner.html</code>, <code>testrunner.css</code>, <code>TestRunner.js</code>) is now provided by the UI5 framework (<code>sap.ui.core</code>) and is served via the <code>serveResources</code> middleware.</p><p>Custom middleware previously referencing <code>serveThemes</code> or <code>testRunner</code> via <code>beforeMiddleware</code> or <code>afterMiddleware</code> will continue to work with automatic remapping and a deprecation warning. See the <a href="./../updates/migrate-v5">v5 migration guide</a> for details.</p></div><p>All available standard middleware are listed below in the order of their execution.</p><p>A project can also add custom middleware to the server by using the <a href="./extensibility/CustomServerMiddleware">Custom Server Middleware Extensibility</a>.</p><table tabindex="0"><thead><tr><th>Middleware</th><th>Description</th></tr></thead><tbody><tr><td><code>csp</code></td><td>See chapter <a href="#csp">csp</a></td></tr><tr><td><code>compression</code></td><td>Standard <a href="http://expressjs.com/en/resources/middleware/compression.html" target="_blank" rel="noreferrer">Express compression middleware</a></td></tr><tr><td><code>cors</code></td><td>Standard <a href="http://expressjs.com/en/resources/middleware/cors.html" target="_blank" rel="noreferrer">Express cors middleware</a></td></tr><tr><td><code>liveReloadClient</code></td><td>See chapter <a href="#livereload">liveReload</a></td></tr><tr><td><code>discovery</code></td><td>See chapter <a href="#discovery">discovery</a></td></tr><tr><td><code>serveResources</code></td><td>See chapter <a href="#serveresources">serveResources</a></td></tr><tr><td><code>versionInfo</code></td><td>See chapter <a href="#versioninfo">versionInfo</a></td></tr><tr><td><code>nonReadRequests</code></td><td>See chapter <a href="#nonreadrequests">nonReadRequests</a></td></tr><tr><td><code>serveIndex</code></td><td>See chapter <a href="#serveindex">serveIndex</a></td></tr></tbody></table><h3 id="csp" tabindex="-1">csp <a class="header-anchor" href="#csp" aria-label="Permalink to &quot;csp&quot;">​</a></h3><p>The Content Security Policy (<a href="https://www.w3.org/TR/CSP/" target="_blank" rel="noreferrer">CSP</a>) middleware is active by default.</p><p>The header <code>content-security-policy</code> can be set by adding URL parameter <code>sap-ui-xx-csp-policy</code> to the request with the policy name as value.</p><p>To set the policy to report-only, append <code>:report-only</code> or <code>:ro</code> to the policy name. E.g. <code>/index.html?sap-ui-xx-csp-policy=sap-target-level-1:report-only</code></p><h4 id="sendsaptargetcsp-parameter" tabindex="-1">sendSAPTargetCSP parameter <a class="header-anchor" href="#sendsaptargetcsp-parameter" aria-label="Permalink to &quot;sendSAPTargetCSP parameter&quot;">​</a></h4><p>The default CSP policies can be modified using parameter <code>sendSAPTargetCSP</code> (<code>--sap-csp-policies</code> when using the CLI). With <code>sendSAPTargetCSP</code> set to <code>true</code> the policies <code>sap-target-level-1</code> and <code>sap-target-level-3</code> policies are activated and send as report-only.</p><h4 id="serve-csp-reports" tabindex="-1">Serve CSP Reports <a class="header-anchor" href="#serve-csp-reports" aria-label="Permalink to &quot;Serve CSP Reports&quot;">​</a></h4><p>Serving of CSP reports can be activated with parameter <code>serveCSPReports</code> (<code>--serve-csp-reports</code> when using the CLI). With <code>serveCSPReports</code> set to <code>true</code>, the CSP reports are collected and can be downloaded from the server path <code>/.ui5/csp/csp-reports.json</code>.</p><h3 id="discovery" tabindex="-1">discovery <a class="header-anchor" href="#discovery" aria-label="Permalink to &quot;discovery&quot;">​</a></h3><p>This middleware lists project files with URLs under several <code>/discovery</code> endpoints. This is exclusively used by the OpenUI5 test suite application.</p><h3 id="livereload" tabindex="-1">liveReload <a class="header-anchor" href="#livereload" aria-label="Permalink to &quot;liveReload&quot;">​</a></h3><p>Live reload automatically refreshes the browser whenever you change a source file in your project — no manual reload needed. This shortens the edit/test cycle during development.</p><h4 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h4><p>Live reload is <strong>enabled by default</strong> with <code>ui5 serve</code>. Open your app in the browser, edit a source file, save — the page reloads.</p><p>To control it:</p><ul><li><strong>CLI flag</strong>: <code>ui5 serve --live-reload</code> / <code>--no-live-reload</code></li><li><strong>Project configuration</strong> (specVersion 5.0+): <code>server.settings.liveReload</code> in <code>ui5.yaml</code>. See <a href="./Configuration">Configuration</a>.</li></ul><p>When the dev server is restarted, the browser automatically reconnects and reloads once the server is back. Saving multiple files at once triggers a single reload, not one per file.</p><h4 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to &quot;Technical Details&quot;">​</a></h4><p>The following describes how the middleware works internally. This is relevant for advanced users and custom middleware developers — not required for regular usage.</p><p>When live reload is active, the UI5 server opens a WebSocket connection that notifies the browser of source changes and triggers a page reload.</p><p>Reloads are driven by the <code>BuildServer</code>, which emits a debounced <code>sourcesChanged</code> event whenever watched source files change. A burst of changes therefore results in a single reload notification.</p><p>The <code>liveReloadClient</code> middleware serves the client script at <code>/.ui5/liveReload/client.js</code>. The script tag is automatically injected into HTML responses by the <code>serveResources</code> middleware.</p><p>To prevent intermediate proxies from idle-closing the WebSocket, the client sends a keepalive message every 30 seconds while the connection is open. The server echoes the same message back.</p><p>When the WebSocket connection is lost (e.g. because the server was restarted), the client polls the WebSocket endpoint every second and reloads the page once the server accepts connections again. While the browser tab is hidden, polling pauses until it becomes visible again.</p><h3 id="serveresources" tabindex="-1">serveResources <a class="header-anchor" href="#serveresources" aria-label="Permalink to &quot;serveResources&quot;">​</a></h3><p>This middleware resolves requests using the <a href="https://github.com/SAP/ui5-fs" target="_blank" rel="noreferrer">ui5-fs</a>-file system abstraction.</p><p>The following file content transformations are executed:</p><ul><li>Escaping non-ASCII characters in <code>.properties</code> translation files based on a project&#39;s <a href="./Configuration#encoding-of-properties-files">configuration</a></li><li>Enhancing the <code>manifest.json</code> with supported locales determined by available <code>.properties</code> <a href="./Builder#generation-of-supported-locales">translation files</a></li></ul><h3 id="versioninfo" tabindex="-1">versionInfo <a class="header-anchor" href="#versioninfo" aria-label="Permalink to &quot;versionInfo&quot;">​</a></h3><p>Generates and serves the version info file <code>/resources/sap-ui-version.json</code>, which is required for several framework functionalities.</p><h3 id="nonreadrequests" tabindex="-1">nonReadRequests <a class="header-anchor" href="#nonreadrequests" aria-label="Permalink to &quot;nonReadRequests&quot;">​</a></h3><p>Answers all non-read requests (POST, PUT, DELETE, etc.) that have not been answered by any other middleware with the 404 &quot;Not Found&quot; status code . This signals the client that these operations are not supported by the server.</p><h3 id="serveindex" tabindex="-1">serveIndex <a class="header-anchor" href="#serveindex" aria-label="Permalink to &quot;serveIndex&quot;">​</a></h3><p>In case a directory has been requested, this middleware renders an HTML with a list of the directory&#39;s content.</p><h2 id="standard-tasks" tabindex="-1">Standard Tasks <a class="header-anchor" href="#standard-tasks" aria-label="Permalink to &quot;Standard Tasks&quot;">​</a></h2><p>As with the UI5 Builder, a set of standard tasks is being executed during a server build. Individual tasks can be included or excluded using the respective CLI options <code>--include-task</code> and <code>--exclude-task</code>.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>See <a href="./Builder#standard-tasks">Builder Standard Tasks</a> for more explanation about each task.</p></div><h2 id="build-cache-control" tabindex="-1">Build Cache Control <a class="header-anchor" href="#build-cache-control" aria-label="Permalink to &quot;Build Cache Control&quot;">​</a></h2><p>The UI5 Server performs a build of the projects by utilizing <strong>build caches</strong>.</p><p>You can control the build cache behavior using the <code>--cache</code> option:</p><ul><li><code>--cache Default</code> (default): Use the cache if available, create it if missing</li><li><code>--cache Force</code>: Only use the cache; fail if the cache is unavailable or invalid</li><li><code>--cache ReadOnly</code>: Use existing cache but don&#39;t update it (useful for CI/CD)</li><li><code>--cache Off</code>: Disable caching entirely and always perform a full rebuild</li></ul><p>Example:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ui5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cache</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Off</span></span></code></pre></div><p>In this scenario, when a source file changes and a request comes in, the server always performs a full rebuild, even if this source version existed previously.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>By default, build caches created by <code>ui5 build</code> and <code>ui5 serve</code> are <strong>separate and cannot be mixed</strong>. Each command executes a distinct set of tasks, resulting in separate caches tailored to its specific use case. For more details on builder caching, see the <a href="./Builder">UI5 Builder documentation</a>.</p></div><h3 id="watch-mode-behavior" tabindex="-1">Watch Mode Behavior <a class="header-anchor" href="#watch-mode-behavior" aria-label="Permalink to &quot;Watch Mode Behavior&quot;">​</a></h3><p>Once started with <code>ui5 serve</code>, the server automatically monitors changes to the source files throughout the session. When a request arrives, it checks for cached results first and only triggers a rebuild of the respective resources and tasks if no cache is available.</p><ul><li><strong>Monitored files</strong>: All files in your project&#39;s source directories (<code>src/</code>, <code>webapp/</code>, <code>test/</code>, etc.)</li><li><strong>Not monitored</strong>: Configuration files (<code>ui5.yaml</code>, <code>package.json</code>), custom task implementations, and dependency files</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Changes to configuration files or custom tasks require a server restart to take effect.</p></div><h2 id="ssl-certificates" tabindex="-1">SSL Certificates <a class="header-anchor" href="#ssl-certificates" aria-label="Permalink to &quot;SSL Certificates&quot;">​</a></h2><p>When starting the UI5 Server in HTTPS- or HTTP/2 mode, for example by using UI5 CLI parameter <code>--h2</code>, you will be prompted for the automatic generation of a local SSL certificate if necessary.</p><p>Follow the given instructions and enter your password to install the generated certificate as trusted. You can find the generated certificate and corresponding private key under <code>.ui5/server</code> in your user&#39;s home directory.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If Chrome unintentionally redirects an HTTP-URL to HTTPS, you need to delete the HSTS mapping in <a href="chrome://net-internals/#hsts" target="_blank" rel="noreferrer">chrome://net-internals/#hsts</a> by entering the domain name (e.g. localhost) and pressing &quot;delete&quot;.</p></div>`,70))]))}});export{v as __pageData,m as default};
